import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { toast } from 'react-toastify';
import { useAuth } from '../context/AuthContext';
import * as api from '../services/api';
import './Subscribe.css';

const PLANS = {
  monthly: {
    label: 'Monthly',
    price: '£10',
    period: '/month',
    total: '£10/mo',
    saving: null,
    days: 30,
  },
  yearly: {
    label: 'Yearly',
    price: '£96',
    period: '/year',
    total: '£8/mo',
    saving: 'Save 20%',
    days: 365,
  },
};

export default function Subscribe() {
  const { user, isSubscribed, refreshUser } = useAuth();
  const navigate = useNavigate();
  const [selected, setSelected] = useState('monthly');
  const [loading, setLoading] = useState(false);

  const handleSubscribe = async () => {
    if (!user) {
      navigate('/register');
      return;
    }

    setLoading(true);
    try {
      const res = await api.activateSubscription(selected);

      // Refresh context so UI immediately reflects new subscription state
      await refreshUser();

      const endDate = new Date(res.data.user.subscriptionEndDate).toLocaleDateString('en-GB', {
        day: 'numeric', month: 'long', year: 'numeric',
      });

      toast.success(`🎉 ${PLANS[selected].label} plan activated! Valid until ${endDate}`);
      navigate('/dashboard');
    } catch (err) {
      toast.error(err.response?.data?.message || 'Could not activate subscription. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  const handleCancel = async () => {
    if (!window.confirm('Are you sure you want to cancel your subscription?')) return;
    try {
      await api.cancelSubscription();
      await refreshUser();
      toast.info('Subscription cancelled.');
    } catch (err) {
      toast.error('Could not cancel subscription.');
    }
  };

  return (
    <div className="subscribe-page page">
      <div className="container-sm">
        <div className="sub-header">
          <div className="section-label">Membership</div>
          <h1>Choose your plan</h1>
          <p>Every subscription enters you into monthly draws and funds your chosen charity.</p>
        </div>

        {/* Already subscribed notice */}
        {isSubscribed() && (
          <div className="card sub-active-notice">
            <span className="badge badge-green">✓ Active Subscriber</span>
            <p>
              You are on the <strong>{user.plan}</strong> plan.
              Valid until{' '}
              <strong>
                {new Date(user.subscriptionEndDate).toLocaleDateString('en-GB', {
                  day: 'numeric', month: 'long', year: 'numeric',
                })}
              </strong>.
            </p>
            <p style={{ fontSize: '0.85rem', color: 'var(--text-muted)', marginTop: '0.25rem' }}>
              Selecting a plan below will <strong>extend</strong> your current subscription.
            </p>
            <div style={{ display: 'flex', gap: '0.75rem', marginTop: '1rem', flexWrap: 'wrap' }}>
              <button className="btn btn-outline btn-sm" onClick={() => navigate('/dashboard')}>
                Go to Dashboard
              </button>
              <button className="btn btn-danger btn-sm" onClick={handleCancel}>
                Cancel Subscription
              </button>
            </div>
          </div>
        )}

        {/* Plan cards */}
        <div className="plan-cards">
          {Object.entries(PLANS).map(([key, plan]) => (
            <div
              key={key}
              className={`plan-card ${selected === key ? 'selected' : ''}`}
              onClick={() => setSelected(key)}
            >
              {plan.saving && <div className="plan-badge">{plan.saving}</div>}
              <div className="plan-name">{plan.label}</div>
              <div className="plan-price">{plan.price}<span>{plan.period}</span></div>
              <div className="plan-equiv">{plan.total} billed</div>
              <ul className="plan-features">
                <li>✓ Monthly prize draw entry</li>
                <li>✓ Score tracking (5 scores)</li>
                <li>✓ Charity contribution</li>
                <li>✓ {plan.days}-day access</li>
                {key === 'yearly' && <li>✓ Priority support</li>}
              </ul>
              <div className={`plan-radio ${selected === key ? 'checked' : ''}`} />
            </div>
          ))}
        </div>

        {/* Where money goes */}
        <div className="sub-breakdown card">
          <h3>Where your subscription goes</h3>
          <div className="breakdown-items">
            <div className="breakdown-item">
              <span>Prize Pool</span>
              <span className="breakdown-pct">90%</span>
            </div>
            <div className="breakdown-bar">
              <div style={{ width: '90%', background: 'var(--accent)' }} />
            </div>
            <div className="breakdown-item">
              <span>Charity (min 10%)</span>
              <span className="breakdown-pct">10%+</span>
            </div>
            <div className="breakdown-bar">
              <div style={{ width: '10%', background: 'var(--gold)' }} />
            </div>
          </div>
          <p className="breakdown-note">
            You can increase your charity percentage in your dashboard settings.
          </p>
        </div>

        <button
          id="subscribe-btn"
          className="btn btn-primary btn-full btn-lg"
          onClick={handleSubscribe}
          disabled={loading}
        >
          {loading
            ? 'Activating…'
            : isSubscribed()
              ? `Extend with ${PLANS[selected].label} Plan →`
              : `Subscribe ${PLANS[selected].label} →`}
        </button>

        <p className="sub-note">Instant activation. No payment required during preview.</p>
      </div>
    </div>
  );
}
